import React from "react";

const typeStyles = {
  loading: { background: "#e8f0fe", color: "var(--brand)" },
  success: { background: "var(--success-light)", color: "var(--success)" },
  error: { background: "var(--error-light)", color: "var(--error)" },
};

const styles = {
  banner: {
    fontSize: "11px",
    padding: "7px 10px",
    borderRadius: "var(--radius-sm)",
    marginBottom: "14px",
    display: "flex",
    alignItems: "center",
    gap: "8px",
  },
  spinner: {
    width: "12px",
    height: "12px",
    border: "2px solid currentColor",
    borderRightColor: "transparent",
    borderRadius: "50%",
    animation: "spin 0.7s linear infinite",
    flexShrink: 0,
  },
};

/**
 * ApiStatusBanner
 * Props: type ("loading"|"success"|"error"|null), message string
 */
export default function ApiStatusBanner({ type, message }) {
  if (!type || !message) return null;

  return (
    <div style={{ ...styles.banner, ...typeStyles[type] }} role="status" aria-live="polite">
      {type === "loading" && <div style={styles.spinner} />}
      {type === "success" && <span>✓</span>}
      {type === "error" && <span>✗</span>}
      <span>{message}</span>
    </div>
  );
}
